import { css } from "@linaria/core";

import { Border, Colour, Font, Radius, Spacing } from "../../theme";

export const inputBox = css`
    border: ${Border["width-010"]} ${Border["solid"]} ${Colour["border"]};
    border-radius: ${Radius["sm"]};
    background: ${Colour["bg"]};

    &:focus-within,
    &[data-focused="true"] {
        outline-offset: -1px;
        outline: ${Border["width-020"]} ${Border["solid"]}
            ${Colour["border-focus"]};
    }
`;

export const inputBoxReadOnly = css`
    border-color: transparent;
    padding: 0;
    background: transparent !important;

    &:focus-within,
    &[data-focused="true"] {
        outline-color: ${Colour["border-focus"]};
    }
`;

export const inputBoxDisabled = css`
    background: ${Colour["bg-disabled"]};
    cursor: not-allowed;

    &:focus-within,
    &[data-focused="true"] {
        outline-color: ${Colour["border-disabled"]};
    }
`;

export const inputBoxError = css`
    border-color: ${Colour["border-error"]};

    &:focus-within,
    &[data-focused="true"] {
        outline-color: ${Colour["border-error-focus"]};
    }
`;

export const inputBoxNoBorder = css`
    border-color: transparent;
    background: transparent;

    &:focus-within,
    &[data-focused="true"] {
        outline: none;
    }
`;

export const inputWrapper = css`
    display: flex;
    align-items: center;
    position: relative;
    height: max-content;
    width: 100%;
    padding: 0 ${Spacing["spacing-16"]} 0 ${Spacing["spacing-16"]};
`;

export const inputWrapperReadOnly = css`
    padding-left: 0;
`;

export const inputWrapperPositionRight = css`
    flex-direction: row-reverse;
`;

export const basicInput = css`
    ${Font["body-baseline-regular"]}
    color: ${Colour["text"]};
    display: block;
    background: transparent;
    border: none;
    outline: none;
    box-shadow: none;
    padding: 0;
    margin: 0;

    &:disabled {
        color: ${Colour["text-subtler"]};

        &:hover {
            cursor: not-allowed;
        }
    }

    &::placeholder,
    &::-webkit-input-placeholder {
        color: ${Colour["text-subtler"]};
    }

    // Chrome, Safari, Edge, Opera
    &::-webkit-outer-spin-button,
    &::-webkit-inner-spin-button {
        -webkit-appearance: none;
        margin: 0;
    }

    // Safari (remove top shadow)
    --webkit-appearance: none;

    // Firefox
    --moz-appearance: textfield;
`;

export const basicInputSmall = css`
    ${Font["body-md-regular"]}
`;

export const basicButton = css`
    background: transparent;
    border: none;
    outline: none;

    &:focus,
    &:active {
        outline: none;
    }

    &:focus-visible {
        outline: ${Border["width-010"]} ${Border["solid"]}
            ${Colour["border-focus"]};
        border-radius: ${Radius["sm"]};
    }
`;

export const clearButton = css`
    background: transparent;
    border: none;
    outline: none;
    height: auto;
    padding: ${Spacing["spacing-12"]} ${Spacing["spacing-16"]};
    margin: calc(${Spacing["spacing-12"]} * -1)
        calc(${Spacing["spacing-16"]} * -1);
    cursor: pointer;
    color: ${Colour.icon};

    &:focus,
    &:active {
        outline: none;
    }

    &:focus-visible {
        outline: 2px solid ${Colour["border-focus"]};
        border-radius: ${Radius["sm"]};
    }
`;

export const clearIcon = css`
    height: 1.25rem;
    width: 1.25rem;
    vertical-align: middle;
`;

export const clearButtonContainer = css`
    position: absolute;
    display: flex;
    align-items: center;
    right: ${Spacing["spacing-16"]};
`;
